(function (window, $) {
    'use strict';

    function safeText(value) {
        var text = value == null ? '' : String(value);

        if (/^[=+\-@]/.test(text)) {
            return "'" + text;
        }

        return text;
    }

    function toInt(value) {
        var parsed = parseInt(value, 10);
        return isNaN(parsed) ? 0 : parsed;
    }

    function toFloat(value, digits) {
        var parsed = parseFloat(value);

        if (isNaN(parsed)) {
            parsed = 0;
        }

        if (typeof digits === 'number') {
            return parsed.toFixed(digits);
        }

        return parsed;
    }

    function ensureArray(value) {
        return Array.isArray(value) ? value : [];
    }

    function pad(value) {
        return value < 10 ? '0' + value : String(value);
    }

    function buildTimestamp() {
        var now = new Date();

        return [
            now.getFullYear(),
            pad(now.getMonth() + 1),
            pad(now.getDate())
        ].join('') + '-' + [
            pad(now.getHours()),
            pad(now.getMinutes()),
            pad(now.getSeconds())
        ].join('');
    }

    function buildFilename(year) {
        return 'developer-performance-' + safeText(year || new Date().getFullYear()) + '-' + buildTimestamp() + '.xlsx';
    }

    function buildCoverageWindow(report) {
        var fromDate = safeText(report.from_date || '');
        var toDate = safeText(report.to_date || '');

        if (fromDate && toDate) {
            return fromDate + ' to ' + toDate;
        }

        return fromDate || toDate || 'Full financial year';
    }

    function createMerge(merges, rowIndex, startCol, endCol) {
        merges.push({
            s: { r: rowIndex, c: startCol },
            e: { r: rowIndex, c: endCol }
        });
    }

    function appendSectionTitle(rows, merges, title, endCol) {
        var rowIndex = rows.length;
        rows.push([safeText(title)]);
        createMerge(merges, rowIndex, 0, endCol);
    }

    function appendKeyValuePairs(rows, pairs) {
        var index;

        for (index = 0; index < pairs.length; index += 2) {
            var left = pairs[index] || {};
            var right = pairs[index + 1] || {};

            rows.push([
                safeText(left.label || ''),
                left.value == null ? '' : left.value,
                '',
                safeText(right.label || ''),
                right.value == null ? '' : right.value
            ]);
        }
    }

    function appendTable(rows, merges, title, headers, bodyRows, endCol) {
        rows.push([]);
        appendSectionTitle(rows, merges, title, endCol);
        rows.push(headers);

        if (!bodyRows.length) {
            rows.push(['No records found']);
            createMerge(merges, rows.length - 1, 0, endCol);
            return {
                headerRow: rows.length - 2,
                lastRow: rows.length - 1
            };
        }

        bodyRows.forEach(function (row) {
            rows.push(row);
        });

        return {
            headerRow: rows.length - bodyRows.length - 1,
            lastRow: rows.length - 1
        };
    }

    function computeResolutionScore(totalTickets, resolvedTickets) {
        totalTickets = toInt(totalTickets);
        resolvedTickets = toInt(resolvedTickets);

        if (!totalTickets) {
            return 0;
        }

        return Math.round((resolvedTickets / totalTickets) * 100);
    }

    function buildSummaryWorksheet(report) {
        var rows = [];
        var merges = [];
        var overview = report.overview || {};
        var developers = ensureArray(report.developers);
        var totalTickets = 0;
        var totalResolved = 0;
        var scoreSum = 0;
        var summaryHeaders;
        var summaryRows;
        var summaryMeta;

        developers.forEach(function (entry) {
            var summary = entry.summary || {};
            totalTickets += toInt(summary.total_tickets);
            totalResolved += toInt(summary.resolved_tickets);
            scoreSum += computeResolutionScore(summary.total_tickets, summary.resolved_tickets);
        });

        rows.push(['Developer Performance Report']);
        createMerge(merges, 0, 0, 18);
        rows.push([]);

        appendSectionTitle(rows, merges, 'Report Snapshot', 4);
        appendKeyValuePairs(rows, [
            { label: 'Financial Year', value: toInt(report.year) },
            { label: 'Coverage Window', value: buildCoverageWindow(report) },
            { label: 'Generated At', value: safeText(report.generated_at || '') },
            { label: 'Generated By', value: safeText(report.generated_by || 'TRS') },
            { label: 'Total Developers', value: developers.length },
            { label: 'Total Tickets Reviewed', value: totalTickets }
        ]);

        rows.push([]);
        appendSectionTitle(rows, merges, 'Team Overview', 4);
        appendKeyValuePairs(rows, [
            { label: 'Hierarchy Members', value: toInt(overview.total_reports) },
            { label: 'Direct Reports', value: toInt(overview.direct_reports) },
            { label: 'Assigned By You', value: toInt(overview.reviewer_assigned) },
            { label: 'Accepted By Team', value: toInt(overview.accepted_total) },
            { label: 'Open Tickets', value: toInt(overview.open_tickets) },
            { label: 'In Progress Tickets', value: toInt(overview.in_progress_tickets) },
            { label: 'Resolved Tickets', value: toInt(overview.resolved_tickets) },
            { label: 'Closed Tickets', value: toInt(overview.closed_tickets) },
            { label: 'Leave Delegations', value: toInt(overview.delegation_absence) },
            { label: 'Active Delegations', value: toInt(overview.active_delegation_absence) },
            { label: 'Leave Days Total', value: toInt(overview.leave_days_total) },
            { label: 'Present Days Total', value: toInt(overview.present_days_total) },
            { label: 'Resolved Tickets Total', value: totalResolved },
            { label: 'Average Resolution Score', value: developers.length ? Math.round(scoreSum / developers.length) + '%' : '0%' }
        ]);

        rows.push([]);
        appendSectionTitle(rows, merges, 'Developer Summary', 18);
        summaryHeaders = [
            'Developer',
            'Company',
            'Department',
            'Total Tickets',
            'Assigned',
            'Accepted',
            'Resolved',
            'Pending',
            'Active Tickets',
            'You Assigned',
            'Avg Resolution Hours',
            'Invested Hours',
            'Incoming Delegations',
            'Outgoing Delegations',
            'Active Delegations',
            'Direct Reports',
            'Leave Days',
            'Present Days',
            'Score %'
        ];
        rows.push(summaryHeaders);
        summaryMeta = {
            headerRow: rows.length - 1,
            startRow: rows.length
        };

        summaryRows = developers.map(function (entry) {
            var summary = entry.summary || {};
            var detailSummary = ((entry.detail || {}).summary) || {};

            return [
                safeText(summary.name || ''),
                safeText(summary.company_name || ''),
                safeText(summary.department_name || ''),
                toInt(summary.total_tickets),
                toInt(summary.assigned_tickets),
                toInt(summary.accepted_tickets),
                toInt(summary.resolved_tickets),
                toInt(summary.pending_tickets),
                toInt(detailSummary.active_tickets || summary.pending_tickets),
                toInt(summary.reviewer_assigned_tickets),
                toFloat(summary.avg_resolution_hours, 1),
                toFloat(summary.invest_hours, 1),
                toInt(summary.incoming_delegations),
                toInt(summary.outgoing_delegations),
                toInt(summary.active_delegations),
                toInt(summary.direct_reports),
                toInt(summary.leave_days),
                toInt(summary.present_days),
                computeResolutionScore(summary.total_tickets, summary.resolved_tickets)
            ];
        });

        if (!summaryRows.length) {
            rows.push(['No developer data available for the selected year.']);
            createMerge(merges, rows.length - 1, 0, 18);
        } else {
            summaryRows.forEach(function (row) {
                rows.push(row);
            });
        }

        summaryMeta.lastDataRow = rows.length - 1;

        rows.push([]);
        appendSectionTitle(rows, merges, 'Notes', 4);
        rows.push([
            'Each developer has a dedicated sheet with leave days, present days, ticket activity, assignment history, and direct report details.'
        ]);
        createMerge(merges, rows.length - 1, 0, 18);

        var worksheet = XLSX.utils.aoa_to_sheet(rows);
        worksheet['!merges'] = merges;
        worksheet['!cols'] = [
            { wch: 24 }, { wch: 18 }, { wch: 18 }, { wch: 12 }, { wch: 10 },
            { wch: 10 }, { wch: 10 }, { wch: 10 }, { wch: 12 }, { wch: 12 },
            { wch: 16 }, { wch: 14 }, { wch: 18 }, { wch: 18 }, { wch: 16 },
            { wch: 12 }, { wch: 12 }, { wch: 12 }, { wch: 10 }
        ];

        if (summaryRows.length) {
            worksheet['!autofilter'] = {
                ref: XLSX.utils.encode_range({
                    s: { r: summaryMeta.headerRow, c: 0 },
                    e: { r: summaryMeta.lastDataRow, c: 18 }
                })
            };
        }

        return worksheet;
    }

    function buildDeveloperWorksheet(report, entry) {
        var rows = [];
        var merges = [];
        var summary = entry.summary || {};
        var detail = entry.detail || {};
        var developer = detail.developer || {};
        var detailSummary = detail.summary || {};
        var statusBreakdown = detail.status_breakdown || {};
        var monthlyVolume = ensureArray(detail.monthly_volume);
        var assignmentBreakdown = ensureArray(detail.assignment_breakdown);
        var currentTickets = ensureArray(detail.current_tickets);
        var acceptedTickets = ensureArray(detail.accepted_tickets);
        var assignedTickets = ensureArray(detail.assigned_tickets);
        var subordinates = ensureArray(detail.subordinates);
        var departmentStatus = ensureArray(detail.department_status);
        var score = computeResolutionScore(summary.total_tickets, summary.resolved_tickets);

        rows.push(['Developer Performance Report']);
        createMerge(merges, 0, 0, 6);
        rows.push([safeText(developer.name || summary.name || 'Developer')]);
        createMerge(merges, 1, 0, 6);
        rows.push([]);

        appendSectionTitle(rows, merges, 'Profile Snapshot', 4);
        appendKeyValuePairs(rows, [
            { label: 'Company', value: safeText(developer.company_name || summary.company_name || 'TRS') },
            { label: 'Department', value: safeText(developer.department_name || summary.department_name || 'No Department') },
            { label: 'Financial Year', value: toInt(report.year) },
            { label: 'Coverage Window', value: buildCoverageWindow(report) },
            { label: 'Generated At', value: safeText(report.generated_at || '') },
            { label: 'Generated By', value: safeText(report.generated_by || 'TRS') }
        ]);

        rows.push([]);
        appendSectionTitle(rows, merges, 'Performance Metrics', 4);
        appendKeyValuePairs(rows, [
            { label: 'Total Tickets', value: toInt(detailSummary.total_tickets || summary.total_tickets) },
            { label: 'Assigned Tickets', value: toInt(summary.assigned_tickets) },
            { label: 'Accepted Tickets', value: toInt(detailSummary.accepted_tickets || summary.accepted_tickets) },
            { label: 'Resolved Tickets', value: toInt(detailSummary.resolved_tickets || summary.resolved_tickets) },
            { label: 'Pending Tickets', value: toInt(detailSummary.pending_tickets || summary.pending_tickets) },
            { label: 'Active Tickets', value: toInt(detailSummary.active_tickets || summary.pending_tickets) },
            { label: 'You Assigned', value: toInt(detailSummary.reviewer_assigned_tickets || summary.reviewer_assigned_tickets) },
            { label: 'Direct Reports', value: toInt(detailSummary.direct_reports || summary.direct_reports) },
            { label: 'Incoming Delegations', value: toInt(detailSummary.incoming_delegations || summary.incoming_delegations) },
            { label: 'Outgoing Delegations', value: toInt(detailSummary.outgoing_delegations || summary.outgoing_delegations) },
            { label: 'Active Delegations', value: toInt(detailSummary.active_delegations || summary.active_delegations) },
            { label: 'Leave Days', value: toInt(detailSummary.leave_days || summary.leave_days) },
            { label: 'Present Days', value: toInt(detailSummary.present_days || summary.present_days) },
            { label: 'Resolution Score', value: score + '%' },
            { label: 'Avg Resolution Hours', value: toFloat(detailSummary.avg_resolution_hours || summary.avg_resolution_hours, 1) },
            { label: 'Invested Hours', value: toFloat(detailSummary.invest_hours || summary.invest_hours, 1) }
        ]);

        appendTable(rows, merges, 'Ticket Status Breakdown', ['Status', 'Count'], [
            ['Open', toInt(statusBreakdown.open_tickets)],
            ['In Progress', toInt(statusBreakdown.in_progress_tickets)],
            ['Resolved', toInt(statusBreakdown.resolved_tickets)],
            ['Closed', toInt(statusBreakdown.closed_tickets)]
        ], 1);

        appendTable(rows, merges, 'Monthly Ticket Volume', ['Month', 'Tickets'], monthlyVolume.map(function (row) {
            return [safeText(row.label || ''), toInt(row.count)];
        }), 1);

        appendTable(rows, merges, 'Assignment Sources', ['Assigner', 'Count'], assignmentBreakdown.map(function (row) {
            return [safeText(row.assigner_name || ''), toInt(row.assign_count)];
        }), 1);

        appendTable(rows, merges, 'Department Status Snapshot', ['Department', 'Open', 'In Progress', 'Resolved', 'Closed'], departmentStatus.map(function (row) {
            return [
                safeText(row.department_name || ''),
                toInt(row.open_tickets),
                toInt(row.in_progress_tickets),
                toInt(row.resolved_tickets),
                toInt(row.closed_tickets)
            ];
        }), 4);

        appendTable(rows, merges, 'Current Tickets', ['Ticket ID', 'Title', 'Owner', 'Status', 'Resolve Readiness', 'Days Open', 'Created At'], currentTickets.map(function (row) {
            return [
                toInt(row.ticket_id),
                safeText(row.title || ''),
                safeText(row.owner_name || ''),
                safeText(row.status_name || ''),
                toInt(row.can_resolve) === 1 ? 'Ready' : 'Blocked by task',
                toInt(row.days_open),
                safeText(row.created_at || '')
            ];
        }), 6);

        appendTable(rows, merges, 'Accepted Tickets', ['Ticket ID', 'Title', 'Owner', 'Status', 'Accepted At'], acceptedTickets.map(function (row) {
            return [
                toInt(row.ticket_id),
                safeText(row.title || ''),
                safeText(row.owner_name || ''),
                safeText(row.status_name || ''),
                safeText(row.accepted_at || '')
            ];
        }), 4);

        appendTable(rows, merges, 'Assigned Tickets', ['Ticket ID', 'Title', 'Assigner', 'Action', 'Status', 'Assigned At'], assignedTickets.map(function (row) {
            return [
                toInt(row.ticket_id),
                safeText(row.title || ''),
                safeText(row.assigner_name || ''),
                safeText(row.action_type || ''),
                safeText(row.status_name || ''),
                safeText(row.assigned_at || '')
            ];
        }), 5);

        appendTable(rows, merges, 'Direct Reports', ['Name', 'Role', 'Company', 'Email'], subordinates.map(function (row) {
            return [
                safeText(row.name || ''),
                safeText(row.role_name || ''),
                safeText(row.company_name || ''),
                safeText(row.email || '')
            ];
        }), 3);

        var worksheet = XLSX.utils.aoa_to_sheet(rows);
        worksheet['!merges'] = merges;
        worksheet['!cols'] = [
            { wch: 14 },
            { wch: 34 },
            { wch: 24 },
            { wch: 18 },
            { wch: 18 },
            { wch: 12 },
            { wch: 22 }
        ];

        return worksheet;
    }

    function buildSheetName(name, usedNames) {
        var baseName = safeText(name || 'Developer')
            .replace(/[\\\/\?\*\[\]\:]/g, ' ')
            .replace(/\s+/g, ' ')
            .trim();
        var candidate;
        var suffix = 1;

        if (!baseName) {
            baseName = 'Developer';
        }

        baseName = baseName.substring(0, 31);
        candidate = baseName;

        while (usedNames[candidate]) {
            var marker = ' (' + suffix + ')';
            candidate = baseName.substring(0, Math.max(0, 31 - marker.length)) + marker;
            suffix += 1;
        }

        usedNames[candidate] = true;

        return candidate;
    }

    function buildWorkbook(report) {
        var workbook = XLSX.utils.book_new();
        var usedNames = {};

        workbook.Props = {
            Title: 'Developer Performance ' + safeText(report.year || ''),
            Subject: 'TRS Developer Performance Export',
            Author: safeText(report.generated_by || 'TRS'),
            Company: 'TRS',
            CreatedDate: new Date()
        };

        XLSX.utils.book_append_sheet(workbook, buildSummaryWorksheet(report), buildSheetName('Summary', usedNames));

        ensureArray(report.developers).forEach(function (entry) {
            var summary = entry.summary || {};
            var detail = entry.detail || {};
            var developer = detail.developer || {};
            var name = developer.name || summary.name || 'Developer';

            XLSX.utils.book_append_sheet(
                workbook,
                buildDeveloperWorksheet(report, entry),
                buildSheetName(name, usedNames)
            );
        });

        return workbook;
    }

    function setButtonBusy(button, isBusy) {
        var $button = $(button);
        var defaultLabel = $button.data('default-label') || $button.text();

        if (!$button.data('default-label')) {
            $button.data('default-label', defaultLabel);
        }

        $button.prop('disabled', !!isBusy);
        $button.text(isBusy ? 'Preparing .xlsx...' : defaultLabel);
    }

    function readErrorMessage(xhr, fallbackMessage) {
        if (xhr && xhr.responseJSON && xhr.responseJSON.message) {
            return xhr.responseJSON.message;
        }

        return fallbackMessage;
    }

    function download(options) {
        options = options || {};

        if (!options.button || $(options.button).prop('disabled')) {
            return;
        }

        if (typeof XLSX === 'undefined' || !XLSX.utils || typeof XLSX.writeFile !== 'function') {
            window.alert('Excel export library is unavailable right now.');
            return;
        }

        if (!options.dataUrl) {
            window.alert('Excel export endpoint is unavailable right now.');
            return;
        }

        setButtonBusy(options.button, true);

        $.ajax({
            url: options.dataUrl,
            type: 'GET',
            dataType: 'json',
            data: {
                year: options.year,
                from_date: options.fromDate || '',
                to_date: options.toDate || ''
            }
        }).done(function (response) {
            if (!response || response.status !== true || !response.report) {
                setButtonBusy(options.button, false);
                window.alert((response && response.message) ? response.message : 'Export data unavailable.');
                return;
            }

            window.setTimeout(function () {
                try {
                    XLSX.writeFile(buildWorkbook(response.report), buildFilename(response.report.year), {
                        compression: true
                    });
                } catch (error) {
                    window.alert('Unable to generate the Excel file.');
                }

                setButtonBusy(options.button, false);
            }, 20);
        }).fail(function (xhr) {
            setButtonBusy(options.button, false);
            window.alert(readErrorMessage(xhr, 'Unable to prepare the Excel export.'));
        });
    }

    window.DeveloperPerformanceExporter = {
        download: download
    };
})(window, jQuery);
